class Solution:
    def longestBalanced(self, s):
        from collections import Counter
        n = len(s)
        best = 0
        for i in range(n):
            for j in range(i, n):
                c = Counter(s[i:j+1])
                vals = list(c.values())
                if len(set(vals)) == 1:
                    best = max(best, j - i + 1)
        return best

