class Solution:
    def longestBalanced(self, s):
        n = len(s)
        best = 0
        for i in range(n):
            cnt = [0] * 26
            distinct = 0
            mx = 0
            for j in range(i, n):
                idx = ord(s[j]) - 97
                if cnt[idx] == 0:
                    distinct += 1
                cnt[idx] += 1
                if cnt[idx] > mx:
                    mx = cnt[idx]
                if mx * distinct == j - i + 1:
                    best = max(best, j - i + 1)
        return best

