var longestBalanced = function(s) {
    const n = s.length;
    let best = 0;
    for (let i = 0; i < n; i++) {
        const cnt = new Array(26).fill(0);
        let distinct = 0;
        let mx = 0;
        for (let j = i; j < n; j++) {
            const idx = s.charCodeAt(j) - 97;
            if (cnt[idx] === 0) distinct++;
            cnt[idx]++;
            if (cnt[idx] > mx) mx = cnt[idx];
            if (mx * distinct === j - i + 1) {
                if (j - i + 1 > best) best = j - i + 1;
            }
        }
    }
    return best;
};
